def sha(rel):
    return hashlib.sha256((root/rel).read_bytes()).hexdigest()
def rows(rel):
    path=root/rel
    if path.suffix.lower()=='.csv':
        return max(sum(1 for _ in path.open(encoding='utf-8'))-1,0)
    return 1
